var currentLang = 'en';

function setLanguage(lang) {
    currentLang = lang;
    var translations = i18nData[lang];
    if (!translations) return;

    document.querySelectorAll('[data-i18n]').forEach(function (el) {
        var key = el.getAttribute('data-i18n');
        if (translations[key] !== undefined) {
            el.textContent = translations[key];
            el.style.display = translations[key] === '' ? 'none' : '';
        }
    });

    document.querySelectorAll('[data-i18n-html]').forEach(function (el) {
        var key = el.getAttribute('data-i18n-html');
        if (translations[key] !== undefined) {
            el.innerHTML = translations[key];
            el.style.display = translations[key] === '' ? 'none' : '';
        }
    });

    document.documentElement.lang = lang === 'zh-cn' ? 'zh-CN' : lang === 'zh-tw' ? 'zh-TW' : 'en';

    document.querySelectorAll('.lang-btn').forEach(function (btn) {
        btn.classList.toggle('active', btn.getAttribute('data-lang') === lang);
    });
}

/* ===== Page switching ===== */
function switchPage(pageId) {
    document.querySelectorAll('.page-section').forEach(function (sec) {
        sec.classList.remove('active');
    });
    var target = document.getElementById('page-' + pageId);
    if (target) {
        target.classList.add('active');
    }

    var floatingBox = document.querySelector('.floating-contact-box');
    if (floatingBox) {
        floatingBox.style.display = (pageId === 'aqueous-battery-service') ? 'block' : 'none';
    }

    window.scrollTo({ top: 0, behavior: 'smooth' });
}

/* ===== Contact form: localStorage persistence ===== */
function saveContact(data) {
    var submissions = JSON.parse(localStorage.getItem('ces_contact_submissions') || '[]');
    data.submitted_at = new Date().toISOString();
    submissions.push(data);
    localStorage.setItem('ces_contact_submissions', JSON.stringify(submissions));
}

/* ===== DOM Ready ===== */
document.addEventListener('DOMContentLoaded', function () {
    var navItems = document.querySelectorAll('.nav-item');

    navItems.forEach(function (item) {
        item.addEventListener('click', function (e) {
            e.preventDefault();
            navItems.forEach(function (el) { el.classList.remove('active'); });
            this.classList.add('active');
            var pageId = this.getAttribute('data-page');
            switchPage(pageId);
        });
    });

    /* Language switcher */
    document.querySelectorAll('.lang-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            setLanguage(this.getAttribute('data-lang'));
        });
    });

    /* Sub-nav tab switching */
    document.querySelectorAll('.sub-nav-item').forEach(function (item) {
        item.addEventListener('click', function (e) {
            e.preventDefault();
            var parent = this.closest('.subpage-layout');
            parent.querySelectorAll('.sub-nav-item').forEach(function (el) {
                el.classList.remove('active');
            });
            this.classList.add('active');
            var tabId = this.getAttribute('data-subtab');
            parent.querySelectorAll('.sub-tab-panel').forEach(function (panel) {
                panel.classList.remove('active');
            });
            var target = document.getElementById('subtab-' + tabId);
            if (target) target.classList.add('active');
        });
    });

    /* Contact form submission */
    var form = document.getElementById('contact-form');
    if (form) {
        form.addEventListener('submit', function (e) {
            e.preventDefault();
            var data = {
                name: document.getElementById('cf-name').value.trim(),
                email: document.getElementById('cf-email').value.trim(),
                phone: document.getElementById('cf-phone').value.trim(),
                organization: document.getElementById('cf-org').value.trim(),
                message: document.getElementById('cf-message').value.trim()
            };
            saveContact(data);
            form.style.display = 'none';
            document.getElementById('form-success').style.display = 'block';
        });
    }

    /* Info modal (under construction) */
    var modal = document.getElementById('info-modal');
    var modalClose = document.getElementById('info-modal-close');

    document.querySelectorAll('.info-link').forEach(function (link) {
        link.addEventListener('click', function (e) {
            e.preventDefault();
            modal.classList.add('active');
        });
    });

    if (modalClose) {
        modalClose.addEventListener('click', function () {
            modal.classList.remove('active');
        });
    }

    if (modal) {
        modal.addEventListener('click', function (e) {
            if (e.target === modal) {
                modal.classList.remove('active');
            }
        });
    }
});
